use std::collections::HashMap;
use std::fs;
use std::io::{self, Write};

struct CSSMinifier {
    properties: HashMap<String, Vec<String>>
}

impl CSSMinifier {
    fn new() -> Self {
        CSSMinifier { properties: HashMap::new() }
    }

    fn process_directory(path: &str) -> io::Result<Self> {
        let mut minifier = CSSMinifier::new();
        let entries = fs::read_dir(path)?;

        for entry in entries {
            let entry = entry?;
            let path = entry.path();
            if path.is_file() && path.extension().map_or(false, |ext| ext == "css") {
                match fs::read_to_string(&path) {
                    Ok(content) => {
                        minifier.add_declarations(&content);
                    }
                    Err(e) => {
                        eprintln!("Could not read file {:?}: {}", &path, e);
                    }
                }
            }
        }
        Ok(minifier)
    }

    fn add_declarations(&mut self, content: &str) {
        let mut _current_property = String::new();
        let mut in_rule = false;

        for line in content.lines() {
            let trimmed = line.trim();
            if trimmed.is_empty() { continue; }

            if trimmed.contains(":") && !trimmed.contains("{") {
                let parts: Vec<&str> = trimmed.split(':').collect();
                if parts.len() == 2 {
                    let prop = parts[0].trim().to_lowercase();
                    let value = parts[1].trim();
                    self.properties.entry(prop).or_insert_with(Vec::new).push(value.to_string());
                }
            } else if trimmed.ends_with("{") {
                in_rule = true;
            } else if in_rule && trimmed.contains("}") {
                in_rule = false;
            }
        }
    }

    fn write_output(&self, output_path: &str) -> io::Result<()> {
        let mut sorted_properties: Vec<String> = self.properties.keys().cloned().collect();
        sorted_properties.sort();

        let mut output = String::new();
        for prop in sorted_properties {
            if let Some(values) = self.properties.get(&prop) {
                output.push_str(&format!("{} {}", &prop, values.join(", ")));
                output.push_str(";n");
            }
        }

        fs::write(output_path, output)
    }
}

fn main() -> io::Result<()> {
    let input_dir = "./source_css";
    if !std::path::Path::new(input_dir).exists() {
        eprintln!("Please create a directory named 'source_css' and place some CSS files inside it.");
        return Ok(());
    }

    let minifier = CSSMinifier::process_directory(input_dir)?;
    minifier.write_output("minified_output.css")?;
    print!("Successfully processed all files and wrote output to minified_output.cssn");
    Ok(())
}

use std::fs::File;
use std::io::{self, BufReader, Read};

struct PricingData {
    inputs: Vec<f64>,
}

fn load_data(filepath: &str) -> io::Result<PricingData> {
    let file = File::open(filepath)?;
    let mut reader = BufReader::new(file);
    let mut buffer = String::new();
    reader.read_to_string(&mut buffer)?;

    let mut inputs = Vec::new();
    for line in buffer.lines() {
        if let Ok(value) = line.trim().parse::<f64>() {
            inputs.push(value);
        }
    }

    Ok(PricingData { inputs })
}

fn main() -> io::Result<()> {
    let data_file = "simulation_inputs.txt";

    std::fs::write(data_file, "10.5n2.1n99.0");

    match load_data(data_file) {
        Ok(pricing_data) => {
            println!("Successfully loaded {} initial parameters.", pricing_data.inputs.len());
            for i in 0..std::cmp::min(3, pricing_data.inputs.len()) {
                println!("Input parameter {}: {}", i + 1, pricing_data.inputs[i]);
            }
        }
        Err(e) => {
            eprintln!("Could not load data: {}", e);
        }
    }

    Ok(())
}

use std::fs::File;
use std::io::{self, Read};
use std::sync::Arc;
use rayon::prelude::*;

struct DataStore {
    files: Vec<String>,
}

impl DataStore {
    fn new(file_names: Vec<String>) -> Self {
        DataStore { files: file_names }
    }

    fn batch_read_data(&self, ids: &[u32]) -> io::Result<Vec<String>> {
        let paths = Arc::new(self.files.clone());
        let results: Vec<io::Result<String>> = ids.par_iter().map(|&id| {
            if let Some(path) = paths.get(id as usize) {
                match File::open(path) {
                    Ok(mut file) => {
                        let mut contents = String::new();
                        file.read_to_string(&mut contents).map(|_| contents)
                    },
                    Err(e) => Err(e),
                }
            } else {
                Ok("".to_string())
            }
        }).collect();

        let mut final_results = Vec::with_capacity(ids.len());
        for result in results {
            match result {
                Ok(s) => final_results.push(s),
                Err(e) => return Err(e),
            }
        }
        Ok(final_results)
    }
}

use std::fs::File;
use std::io::{self, BufReader, BufRead, Write};

struct HostRecord {
    hostname: String,
    service: String,
}

fn process_log_data(input_path: &str, output_path: &str) -> io::Result<()> {
    let file = File::open(input_path)?; 
    let reader = BufReader::new(file);

    let mut records: Vec<HostRecord> = Vec::new();

    for line in reader.lines() {
        let line_content = line?;
        if line_content.contains("[INFO]") && line_content.contains("webauthn") {
            let parts: Vec<&str> = line_content.split(" ").collect();
            if parts.len() >= 3 {
                let hostname = parts.get(0).unwrap_or(&"unknown").trim_matches('<');
                let service = parts.last().map(|s| s.split(':').last().unwrap_or(&"default")).unwrap_or(&"default").to_string();
                records.push(HostRecord {
                    hostname: String::from(hostname),
                    service: service,
                });
            }
        }
    }

    let mut output_file = File::create(output_path)?; 
    for record in records {
        writeln!(output_file, "Host: {}, Service: {}", record.hostname, record.service)?; 
    }

    Ok(())
}
